# DONUT CHART (using QPainter)
# ==============================================================================
class _DonutChart(QtWidgets.QWidget):
    def __init__(self, parent=None):
        super().__init__(parent)
        self.setMinimumSize(130, 130)
        self.slices = []
        self.total_label = "Total"

    def set_data(self, slices: list[tuple[str, int, str]], total_label: str = "Total"):
        self.slices = slices
        self.total_label = total_label
        self.update()

    def paintEvent(self, event):
        p = QPainter(self)
        p.setRenderHint(QPainter.RenderHint.Antialiasing)
        
        w, h = self.width(), self.height()
        size = min(w, h) - 16
        x = (w - size) // 2
        y = (h - size) // 2
        rect = QtCore.QRectF(x, y, size, size)
        
        total = sum(val for _, val, _ in self.slices)
        if total == 0:
            p.setBrush(QBrush(QColor("#eff6ff")))
            p.setPen(Qt.PenStyle.NoPen)
            p.drawEllipse(rect)
            
            hole = size * 0.60
            hx = (w - hole) / 2
            hy = (h - hole) / 2
            p.setBrush(QBrush(QColor(_WHITE)))
            p.drawEllipse(QtCore.QRectF(hx, hy, hole, hole))
            
            # Center label "0"
            p.setPen(QColor(_TEXT_DARK))
            p.setFont(QtGui.QFont("Segoe UI", 16, QtGui.QFont.Weight.Bold))
            p.drawText(QtCore.QRectF(hx, hy - 6, hole, hole / 2 + 8),
                       Qt.AlignmentFlag.AlignCenter, "0")
                       
            p.setFont(QtGui.QFont("Segoe UI", 8))
            p.setPen(QColor(_TEXT_GREY))
            p.drawText(QtCore.QRectF(hx, hy + hole / 2 - 10, hole, 16),
                       Qt.AlignmentFlag.AlignCenter, self.total_label)
            return
            
        start = 90 * 16
        for _, val, col in self.slices:
            if val == 0:
                continue
            span = int(round(val / total * 360 * 16))
            p.setBrush(QBrush(QColor(col)))
            p.setPen(Qt.PenStyle.NoPen)
            p.drawPie(rect, start, -span)
            start -= span
            
        # Draw central white hole
        hole = size * 0.62
        hx = (w - hole) / 2
        hy = (h - hole) / 2
        p.setBrush(QBrush(QColor(_WHITE)))
        p.drawEllipse(QtCore.QRectF(hx, hy, hole, hole))
        
        # Center labels
        p.setPen(QColor(_TEXT_DARK))
        p.setFont(QtGui.QFont("Segoe UI", 16, QtGui.QFont.Weight.Bold))
        p.drawText(QtCore.QRectF(hx, hy - 6, hole, hole / 2 + 8),
                   Qt.AlignmentFlag.AlignCenter, str(total))
                   
        p.setFont(QtGui.QFont("Segoe UI", 8))
        p.setPen(QColor(_TEXT_GREY))
        p.drawText(QtCore.QRectF(hx, hy + hole / 2 - 10, hole, 16),
                   Qt.AlignmentFlag.AlignCenter, self.total_label)
        p.end()

# ==============================================================================
# LINE TREND CHART (using QPainter)
# ==============================================================================
class _TrendChart(QtWidgets.QWidget):
    def __init__(self, parent=None):
        super().__init__(parent)
        self.setMinimumHeight(150)
        self.points = [10, 18, 25, 15, 30, 20, 28, 15, 22, 32, 28, 34, 32, 28, 36, 48, 42]

    def paintEvent(self, event):
        painter = QPainter(self)
        painter.setRenderHint(QPainter.RenderHint.Antialiasing)
        
        w, h = self.width(), self.height()
        margin_left = 30
        margin_bottom = 20
        margin_top = 10
        margin_right = 10
        
        chart_w = w - margin_left - margin_right
        chart_h = h - margin_top - margin_bottom
        
        # Grid lines (horizontal)
        grid_values = [0, 10, 20, 30, 40, 50]
        painter.setFont(QtGui.QFont("Segoe UI", 8))
        for gv in grid_values:
            y = margin_top + chart_h - (gv / 50.0) * chart_h
            # Draw line
            pen = QtGui.QPen(QColor("#f3f4f6"), 1, QtCore.Qt.PenStyle.SolidLine)
            painter.setPen(pen)
            painter.drawLine(QtCore.QPointF(margin_left, y), QtCore.QPointF(w - margin_right, y))
            
            # Label
            painter.setPen(QColor(_TEXT_GREY))
            painter.drawText(QtCore.QRectF(0, y - 6, margin_left - 5, 12),
                             Qt.AlignmentFlag.AlignRight | Qt.AlignmentFlag.AlignVCenter, str(gv))
            
        # Draw path
        point_coords = []
        for i, val in enumerate(self.points):
            x = margin_left + i * chart_w / (len(self.points) - 1)
            y = margin_top + chart_h - (val / 50.0) * chart_h
            point_coords.append((x, y))
            
        # Create gradient path
        if point_coords:
            path = QtGui.QPainterPath()
            path.moveTo(point_coords[0][0], point_coords[0][1])
            for pt in point_coords[1:]:
                path.lineTo(pt[0], pt[1])
                
            # Fill path
            fill_path = QtGui.QPainterPath(path)
            fill_path.lineTo(point_coords[-1][0], margin_top + chart_h)
            fill_path.lineTo(point_coords[0][0], margin_top + chart_h)
            fill_path.closeSubpath()
            
            gradient = QtGui.QLinearGradient(0, margin_top, 0, margin_top + chart_h)
            gradient.setColorAt(0.0, QColor(88, 112, 255, 60))
            gradient.setColorAt(1.0, QColor(88, 112, 255, 0))
            
            painter.fillPath(fill_path, QtGui.QBrush(gradient))
            
            # Draw line
            line_pen = QtGui.QPen(QColor("#3b82f6"), 2, QtCore.Qt.PenStyle.SolidLine)
            painter.setPen(line_pen)
            painter.drawPath(path)
            
            # Draw points (circles) at key indices: 0 (1 Jun), 4 (7 Jun), 8 (14 Jun), 12 (21 Jun), 15 (30 Jun)
            key_indices = [0, 4, 8, 12, 15]
            for idx in key_indices:
                if idx < len(point_coords):
                    pt = point_coords[idx]
                    painter.setBrush(QBrush(QColor("#ffffff")))
                    painter.setPen(QtGui.QPen(QColor("#3b82f6"), 2))
                    painter.drawEllipse(QtCore.QPointF(pt[0], pt[1]), 4, 4)
                    
        # X Axis labels
        x_labels = [("1 Jun", 0), ("7 Jun", 4), ("14 Jun", 8), ("21 Jun", 12), ("30 Jun", 15)]
        painter.setPen(QColor(_TEXT_GREY))
        for text, idx in x_labels:
            if idx < len(point_coords):
                pt = point_coords[idx]
                rect = QtCore.QRectF(pt[0] - 25, margin_top + chart_h + 4, 50, 14)
                painter.drawText(rect, Qt.AlignmentFlag.AlignCenter, text)
                
        painter.end()

