        status = self.status_combo.currentText()

        errors = []
        if not name:
            errors.append("Visitor Name is required.")
        if not company:
            errors.append("Company is required.")
        if purpose.startswith("—"):
            errors.append("Please select a Purpose.")
        if not host:
            errors.append("Host/Contact is required.")
        if not check_in:
            errors.append("Check-in Time is required.")

        if errors:
            self.error_lbl.setText("⚠ " + " • ".join(errors))
            self.error_lbl.setVisible(True)
            return

        self.error_lbl.setVisible(False)
        data = {
            "name": name,
            "company": company,
            "purpose": purpose,
            "host": host,
            "check_in": check_in,
            "check_out": check_out,
            "status": status,
        }
        self.visitor_saved.emit(data)
        self.accept()

